-- Знания ВБ о poehali.dev + сценарии-скрипты

INSERT INTO t_p71821556_real_estate_catalog_.ai_memory (key, value, updated_at) VALUES

('poehali_what', 'poehali.dev — российская платформа для создания SPA через ИИ. Стек: React + Vite + TypeScript на фронте, Python Cloud Functions на бэке, PostgreSQL для БД, S3 для файлов.', NOW()),
('poehali_arch', 'Архитектура проекта: 5 слоёв — Frontend (/src), Backend (/backend), База данных PostgreSQL, Секреты (env), S3-хранилище. Фронт вызывает бэк по HTTP. Бэк имеет доступ к БД и секретам.', NOW()),
('poehali_help', 'Центр поддержки poehali.dev — https://poehali.dev/help (тикетная система). Туда обращаются с проблемами платформы, фича-реквестами. Сообщество — https://t.me/+QgiLIa1gFRY4Y2Iy.', NOW()),
('poehali_publish', 'Публикация сайта: меню админки → «Опубликовать» → выбрать домен poehali.dev или подключить свой. SSL и хостинг настраиваются автоматически.', NOW()),
('poehali_domain', 'Подключение своего домена: «Опубликовать» → «Привязать свой домен» → следовать инструкции по DNS. SSL Lets Encrypt выпускается автоматически.', NOW()),
('poehali_github', 'Подключение GitHub: «Скачать» → «Подключить GitHub» → авторизация → выбор аккаунта/репозитория → код синхронизируется автоматически.', NOW()),
('poehali_export', 'Выгрузка кода: «Скачать» → «Скачать код» (исходники) или «Скачать билд» (готовый HTML+JS+CSS для статичного хостинга).', NOW()),
('poehali_seo_docs', 'Документация по SEO: https://docs.poehali.dev/deploy/seo. По GitHub: https://docs.poehali.dev/deploy/github. По публикации: https://docs.poehali.dev/deploy/publish.', NOW()),

('poehali_functions', 'Cloud Functions — Python 3.11 + поддержка TypeScript. Каждая функция деплоится отдельно. Точка входа: handler(event, context) возвращает dict. URL берётся из func2url.json.', NOW()),
('poehali_func_event', 'event содержит: httpMethod, headers, queryStringParameters, body (string, парсить json.loads), isBase64Encoded, requestContext.identity.sourceIp. context — объект (context.request_id).', NOW()),
('poehali_func_cors', 'CORS: всегда обрабатывать OPTIONS первым делом. В каждый ответ добавлять Access-Control-Allow-Origin: *.', NOW()),
('poehali_func_auth', 'Заголовки авторизации: cloud-провайдер фильтрует Authorization/Cookie. Фронт шлёт Authorization → бэк читает X-Authorization. Бэк ставит X-Set-Cookie → провайдер преобразует в Set-Cookie.', NOW()),
('poehali_func_tests', 'Тесты для каждой функции — в tests.json. Каждый тест обязан содержать method. Все тесты должны проходить.', NOW()),
('poehali_func_timeout', 'Каждая функция имеет таймаут (по умолчанию 30с). Биллинг: вызовы × таймаут. Меньше таймаут — больше вызовов в лимите. Меняется в Ядре → Функции → Настройки.', NOW()),

('poehali_db', 'БД — PostgreSQL. Доступ только из бэка через DATABASE_URL + psycopg2. Только Simple Query Protocol (без параметризации $1/percent-s). Изменения схемы — через миграции в db_migrations/.', NOW()),
('poehali_db_migrate', 'Миграции — файлы V{version}__{description}.sql. Forward-only, без откатов. Инструмент migrate_db применяет и сохраняет файл только при успехе.', NOW()),
('poehali_db_safety', 'Защита БД: запрещены удаление базы целиком и полная очистка таблиц через стандартные инструменты. Разрешено удаление CONSTRAINT/FUNCTION/INDEX/TRIGGER/VIEW.', NOW()),

('poehali_s3', 'S3-хранилище: endpoint https://bucket.poehali.dev, bucket=files, доступ через AWS_ACCESS_KEY_ID + AWS_SECRET_ACCESS_KEY (только в бэке). CDN: cdn.poehali.dev/projects/{KEY_ID}/bucket/...', NOW()),
('poehali_s3_upload', 'Загрузка файлов: base64 в JSON body (НЕ multipart/form-data). На бэке boto3.put_object с ContentType.', NOW()),
('poehali_secrets', 'Секреты доступны бэку через os.environ. Имена UPPERCASE_WITH_UNDERSCORES. Никогда не логировать и не возвращать значения в API.', NOW()),

('poehali_frontend_rules', 'Frontend: использовать @/ для импортов, shadcn/ui для UI, lucide-react через wrapper Icon (size, fallback). Шрифты Google. Цвета через CSS-переменные в tailwind.config.ts и src/index.css.', NOW()),
('poehali_no_sql_frontend', 'НИКОГДА: SQL во фронтенде, секреты во фронтенде, прямой доступ к БД из фронта, бинарные файлы в БД. Только Frontend → Backend (HTTP) → DB/Secrets/S3.', NOW()),

('scenario_no_leads', 'Сценарий «лидов мало/нет». Ответ: 1) проверь форму обратной связи (Настройки → Уведомления) — приходят ли тестовые заявки на email. 2) Метрика/GA4 — есть ли трафик. 3) SEO-индексация в Вебмастере. 4) Если трафик есть, но не пишут — поправь оффер на главной.', NOW()),
('scenario_low_conv', 'Сценарий «низкая конверсия каталога». Ответ: проверь — 1) есть ли у объектов фото и описание (без них конверсия около нуля). 2) Цены адекватны рынку (cap-rate сегмента). 3) Скорость загрузки (PageSpeed). 4) Кнопка «Заявка» видна без скролла. Запусти агента «Улучшить объекты».', NOW()),
('scenario_domain_off', 'Сценарий «домен не работает». Ответ: 1) Проверь DNS-записи у регистратора (A/CNAME согласно инструкции poehali). 2) Подожди до 24 часов на распространение. 3) В админке — Опубликовать → статус домена. 4) Если ошибка SSL — нажми «Перевыпустить сертификат».', NOW()),
('scenario_photos_slow', 'Сценарий «фото долго грузятся». Ответ: открой Настройки → Оптимизация фото → сканировать. ВБ найдёт файлы больше 500 КБ и предложит сжатие. После сжатия — водяной знак не перерисовывается.', NOW()),
('scenario_seo_drop', 'Сценарий «упали позиции в Яндексе/Google». Ответ: 1) проверь Вебмастер → ошибки индексации, исключённые страницы. 2) Скорость по PageSpeed (мобильная важнее). 3) Свежие AGS/пессимизация в письмах. 4) Запусти агента «SEO» — он пройдётся по объектам без title/description.', NOW()),
('scenario_xml_broken', 'Сценарий «фид XML не принимается Авито/ЦИАН». Ответ: открой Настройки → Фиды → проверка фида. Самые частые ошибки — отсутствие обязательных тегов, неправильный category-id, фото без URL. Лог в разделе «История генерации».', NOW()),
('scenario_backup', 'Сценарий «нужен бэкап». Ответ: меню → Настройки → Экспорт/импорт → «Скачать архив». Получишь дамп БД и фото одним zip. Делай еженедельно перед массовыми правками.', NOW()),
('scenario_new_feature', 'Сценарий «хочу новую функцию на сайте». Ответ: 1) опиши кратко цель и сценарий использования. 2) Если фича про объекты/лиды/SEO — могу реализовать сразу. 3) Если интеграция с внешним сервисом — нужны API-ключи и доки. 4) Сложная архитектура — оценю в часах и предложу план.', NOW()),
('scenario_slow_admin', 'Сценарий «админка тормозит». Ответ: 1) очисти кэш браузера (Ctrl+F5). 2) Открой DevTools → Network → найди медленные запросы (>2с). 3) Если медленные SQL — нужен индекс или оптимизация выборки. Покажи скрин — разберусь.', NOW()),
('scenario_500_error', 'Сценарий «ошибка 500 на сайте». Ответ: 1) открой Ядро → Логи функций → найди свежие красные строки. 2) Точное сообщение об ошибке. 3) Если БД — проверь миграции, кончилось ли место. 4) Если внешний API — проверь секрет/лимиты.', NOW()),
('scenario_listing_stuck', 'Сценарий «объект не публикуется». Ответ: 1) проверь статус — должен быть active, не draft и не archived. 2) Все обязательные поля заполнены? (title, price, area, category). 3) Хотя бы одно фото есть. 4) Если статус active, но в каталоге нет — обнови фид и проверь фильтры.', NOW()),
('scenario_email_silent', 'Сценарий «не приходят письма с заявками». Ответ: 1) Настройки → Уведомления → проверь, включены ли email-уведомления. 2) Адрес корректный? 3) Папка «Спам». 4) Если ничего — пришли тестовую заявку через форму и смотри в логи функции leads.', NOW()),
('scenario_price_predict', 'Сценарий «оцени стоимость объекта по адресу/параметрам». Ответ: запусти агента «Аналитика» — он сравнит с базой компании и применит cap-rate сегмента. Для официальной оценки — рекомендую аттестованного оценщика (в роли брокера: всегда такая оговорка).', NOW()),
('scenario_telegram_post', 'Сценарий «настроить автопостинг в Telegram». Ответ: Настройки → Интеграции → Telegram → введи токен бота и chat_id канала. После — Автопостинг → выбери триггер (новый объект, изменение цены). Тест-постом проверь.', NOW()),
('scenario_users_roles', 'Сценарий «добавить нового сотрудника». Ответ: Пользователи → «Добавить». Роли: admin (полный доступ), director (всё кроме настроек безопасности), manager (лиды+объекты), broker (свои объекты+лиды), editor (контент), office_manager (только просмотр+заявки).', NOW()),
('scenario_water_mark', 'Сценарий «убрать/изменить водяной знак». Ответ: Настройки → Брендинг → Водяной знак. Можно отключить полностью, поменять прозрачность, позицию, логотип. Применяется только к новым загрузкам; для старых — запусти переобработку.', NOW()),
('scenario_robots_sitemap', 'Сценарий «как настроить robots.txt и sitemap?». Ответ: sitemap.xml генерируется автоматически на /sitemap.xml — туда попадают все active-объекты и SEO-страницы. robots.txt — в Настройки → SEO. По умолчанию открыто всё кроме /admin.', NOW()),
('scenario_ssl_expired', 'Сценарий «истёк SSL-сертификат». Ответ: Lets Encrypt продлевается автоматически. Если истёк — Опубликовать → твой домен → «Перевыпустить сертификат». Если кнопка не помогает — проверь DNS (A-запись должна указывать на poehali) и открой тикет на /help.', NOW()),
('scenario_meta_pixel', 'Сценарий «подключить Яндекс.Метрику или GA4». Ответ: Настройки → Аналитика → введи номер счётчика Метрики и/или Measurement ID для GA4. Код вставляется автоматически. Проверь в DevTools → Network → запросы к mc.yandex.ru / google-analytics.com.', NOW()),
('scenario_too_long_titles', 'Сценарий «длинные/короткие названия объектов». Ответ: в [ПУЛЬС САЙТА] нет сводки по длине названий. Запусти агента «Улучшить объекты» — он пройдёт по каталогу, найдёт title менее 30 или более 70 символов и предложит правки. Оптимум для SEO: 50-60 символов с городом.', NOW())

ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
